var e=[{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`아침이면 어른들의 고함소리와 철문을 때리는 거친 쇳소리에 눈을 뜬다.`,JPN:`朝になると、大人たちの怒鳴り声と鉄の扉を叩く荒い金属音で目が覚める。`,ENG:`Every morning, I wake up at the sound of the grownups shouting and beating at the metal door.`,TWN:`每天早晨都是在大人們的喊叫聲，和拍打鐵門的聲音中醒來。`},stage:{bg:`WORKSHOP`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:null,text:{KOREA:`웅크린 채 아파하는 아이.`,JPN:`うずくまったまま痛がる子。`,ENG:`A child is groaning in pain in the fetal position.`,TWN:`痛到蜷曲著身體的孩子`},stage:{bg:`WORKSHOP`,slots:{L:{char_id:`CENSORED_VOICE_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:null,text:{KOREA:`깡통을 받고 내쫓기듯 동냥을 나서는 아이.`,JPN:`物乞い用の缶を渡され、追い出されるように物乞いに出る子。`,ENG:`Another child is pushed outside with a begging can in his hand for begging.`,TWN:`拿著空罐被趕出去乞討的孩子`},stage:{bg:`WORKSHOP`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:null,text:{KOREA:`굶주림에 지쳐 꿈쩍 않는 아이들.`,JPN:`飢えに飢えて、ぴくりとも動けなくなった子どもたち。`,ENG:`Children are too hungry to even move.`,TWN:`餓到兩眼發昏的孩子`},stage:{bg:`WORKSHOP`,slots:{L:null,C:null,R:{char_id:`CENSORED_VOICE_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L15_1`,type:`dialog`,speaker:null,text:{KOREA:`익숙한 소리.`,JPN:`聞き慣れた音。`,ENG:`Familiar sounds.`,TWN:`熟悉的聲音`},stage:{bg:`WORKSHOP`,slots:{L:null,C:null,R:{char_id:`CENSORED_VOICE_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L16_1`,type:`dialog`,speaker:null,text:{KOREA:`낯선 광경.`,JPN:`見慣れない光景。`,ENG:`Unfamiliar scenes.`,TWN:`陌生的景況`},stage:{bg:`WORKSHOP`,slots:{L:null,C:null,R:{char_id:`CENSORED_VOICE_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L17_1`,type:`dialog`,speaker:null,text:{KOREA:`이곳이 어릴 적의 그곳이란 걸 알고 있다.`,JPN:`ここが幼い頃のあの場所だということを知っている。`,ENG:`I know I'm back in the old place, where I was a child.`,TWN:`這裡就是小時候的那個地方。`},stage:{bg:`WORKSHOP`,slots:{L:null,C:null,R:{char_id:`CENSORED_VOICE_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L21_1`,type:`dialog`,speaker:null,text:{KOREA:`허름한 창고엔 항상 구석에 쪼그려 앉아 있는 소녀가 있었다.`,JPN:`古びた倉庫の端にはいつも、しゃがんでいる一人の少女がいた。`,ENG:`There was a girl always sitting crouched by herself in the corner of the shabby warehouse.`,TWN:`破舊的倉庫裡，有個女孩總是蹲在角落。`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`GAEUN_CHILD_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:null,text:{KOREA:`이곳의 모두가 그렇듯, 그 소녀도 지쳐 보였다.`,JPN:`ここの誰もがそうであるように、その少女も疲れ果てているように見えた。`,ENG:`Just like everyone else in this place, she looked exhausted.`,TWN:`和這裡的所有人一樣，女孩也露出一臉疲態。`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`GAEUN_CHILD_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:null,text:{KOREA:`소녀는 누구의 눈치도 보지 않았고, 이곳의 생활에 대해 아무런 불만도 하지 않았다.`,JPN:`少女は誰の顔色も伺わず、ここでの生活に対して何の不満も言わなかった。`,ENG:`She didn't pay attention to anyone or complain about her life here.`,TWN:`女孩不在意任何人的目光，也從來不會對這裡的生活發出怨言。`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`GAEUN_CHILD_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:null,text:{KOREA:`그저 자신이 가진 인형에 의지하듯, 조용히 그것을 품에 끌어안고 있을 뿐이었다.`,JPN:`ただ彼女は持っているぬいぐるみに縋るかのように、静かにそれを抱いているだけだった。`,ENG:`She just sat there quietly, clutching a doll tightly, as if her life depended on it.`,TWN:`女孩只是靜靜地抱著她的娃娃，彷彿那個娃娃是她唯一的倚靠。`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`GAEUN_CHILD_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:null,text:{KOREA:`한참을 울고 있던 날이었다.`,JPN:`しばらく泣いていた日のこと。`,ENG:`One day, I cried for a long time.`,TWN:`那天是哭得很慘的一天，`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L28_1`,type:`dialog`,speaker:null,text:{KOREA:`이유는 기억나지 않는다.`,JPN:`理由は思い出せない。`,ENG:`I don't remember why.`,TWN:`原因已經記不清楚。`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L29_1`,type:`dialog`,speaker:null,text:{KOREA:`그 비참한 감옥에서 아이들이 우는 일은 다반사였다.`,JPN:`あの悲惨な牢屋で子どもたちが泣くのは日常茶飯事だった。`,ENG:`Children in that dreadful prison cried all the time.`,TWN:`在那悲慘的監獄裡，孩子們的哭聲是家常便飯。`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L30_1`,type:`dialog`,speaker:null,text:{KOREA:`시끄럽다는 어른의 고함에 주눅이 들어 울음을 삼키고 있을 무렵…`,JPN:`うるさいという大人の怒鳴り声に怯え、涙をのんでいた頃……`,ENG:`A grownup shouted at me, instantly giving me hiccups.`,TWN:`因為大人的斥責聲，而正準備把眼淚往肚子裡吞時…`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L31_1`,type:`dialog`,speaker:null,text:{KOREA:`인형 하나가 눈에 들어왔다.`,JPN:`ぬいぐるみが目に入った。`,ENG:`And then... I saw a doll.`,TWN:`有個娃娃出現在眼前。`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:null,R:null}}}];export{e as default};